  // ============================================================
  // FOUNDATIONS · The Single Stroke Roll
  // ============================================================
  'single-stroke-roll': {
    tagline: "Alternating hands — the most fundamental motion in drumming",
    duration: "15 min",
    focus: "Rudiment / Sticking",
    prerequisites: ['stick-grip', 'counting-eighths'],
    nextLessons: ['double-stroke-roll', 'paradiddle'],
    graduationCriteria: [
      'Quarter, 8th, and 16th densities all flow at ♩=80 without one hand getting weak',
      'Accents (Ex 4) make the pulse audible inside the stream of 16ths',
      'Stick heights match between R and L on every stroke'
    ],
    bodyHtml: `
      <p>The <strong>single stroke roll</strong> is just <em>R L R L R L R L</em> — alternating, evenly spaced. There's nothing easier to describe and almost nothing harder to play <em>perfectly even</em>. Two key ideas: every stroke at the same volume, and your hands at exactly the same height.</p>
      <p>Build speed by adding density (more notes per beat), not by rushing the hands. Quarter → eighth → sixteenth, each at the same tempo. Your hands learn the motion at the slow density, then carry it into the fast one.</p>
    `,
    exercises: [
      {
        title: "1 — Quarter-Note Singles",
        meta: "4/4 · ♩ = 80",
        bpm: 80,
        timeSignature: "4/4",
        repeatBegin: true,
        repeatEnd: true,
        hands: [
          { keys: ['c/5'], duration: 'q', sticking: 'R' },
          { keys: ['c/5'], duration: 'q', sticking: 'L' },
          { keys: ['c/5'], duration: 'q', sticking: 'R' },
          { keys: ['c/5'], duration: 'q', sticking: 'L' }
        ],
        tip: "Sticking: <em>R L R L</em>. One stroke per beat. Watch your stick heights — both sticks should rebound to the same place. If one is higher than the other, even out before adding speed."
      },
      {
        title: "2 — Eighth-Note Singles",
        meta: "4/4 · ♩ = 80",
        bpm: 80,
        timeSignature: "4/4",
        repeatBegin: true,
        repeatEnd: true,
        hands: Array.from({ length: 8 }, (_, i) => ({
          keys: ['c/5'],
          duration: '8',
          sticking: ['R','L'][i % 2]
        })),
        beamGroups: [[2, 8], [2, 8], [2, 8], [2, 8]],
        tip: "Sticking: <em>R L R L R L R L</em>. Same tempo as exercise 1, twice the strokes per beat. The <em>tempo</em> doesn't change; only the <em>density</em> does."
      },
      {
        title: "3 — Sixteenth-Note Singles (The Roll)",
        meta: "4/4 · ♩ = 80",
        bpm: 80,
        timeSignature: "4/4",
        repeatBegin: true,
        repeatEnd: true,
        hands: Array.from({ length: 16 }, (_, i) => ({
          keys: ['c/5'],
          duration: '16',
          sticking: ['R','L'][i % 2]
        })),
        beamGroups: [[4, 16], [4, 16], [4, 16], [4, 16]],
        tip: "Sticking: <em>R L R L · R L R L · R L R L · R L R L</em>. This is the actual single stroke roll. Even though your hands are moving fast, the metronome pulse is unchanged — beat 1 still lands on the same R it did in exercise 1."
      },
      {
        title: "4 — Sixteenths with Accents on the Beat",
        meta: "4/4 · ♩ = 80",
        bpm: 80,
        timeSignature: "4/4",
        repeatBegin: true,
        repeatEnd: true,
        hands: Array.from({ length: 16 }, (_, i) => ({
          keys: ['c/5'],
          duration: '16',
          sticking: ['R','L'][i % 2],
          accent: (i % 4 === 0)
        })),
        beamGroups: [[4, 16], [4, 16], [4, 16], [4, 16]],
        tip: "Same notes as exercise 3, but play the <em>first sixteenth of each beat louder</em> — the <em>&gt;</em> marks show where. Accents land on the R's at counts 1, 2, 3, 4; quiet on every other note. This is how you make the pulse audible inside a stream of even sixteenths."
      }
    ]
  },

