          { keys: ['c/5'], duration: '16', sticking: 'L' },
          { keys: ['g/5/x2'], duration: '16', sticking: 'R' },
          { rest: true, duration: '16' },
          // Beat 3
          { keys: ['g/5/x2'], duration: '16', sticking: 'R' },
          { keys: ['c/5'], duration: '16', sticking: 'L' },
          { keys: ['g/5/x2'], duration: '16', sticking: 'R' },
          { rest: true, duration: '16' },
          // Beat 4
          { keys: ['g/5/x2'], duration: '16', sticking: 'R' },
          { keys: ['c/5'], duration: '16', sticking: 'L' },
          { keys: ['g/5/x2'], duration: '16', sticking: 'R' },
          { rest: true, duration: '16' }
