        bpm: 88,
        timeSignature: "4/4",
        repeatBegin: true,
        repeatEnd: true,
        // 16 sixteenth-note hi-hat hits, snare on 2 and 4 stacked.
        // Sticking RLRL means the snare on beat 2 is played by L while
